def fibonacci(n):
    if n <= 0:
        return []
    elif n == 1:
        return [0]

    seq = [0, 1]
    for i in range(2, n):
        seq.append(seq[i-1] + seq[i-2])
    return seq

# Check if the length matches n for all cases
for i in range(0, 12):
    result = fibonacci(i)
    print(f"fibonacci({i}): length={len(result)}, result={result}")
